import { expect, test, describe } from "vitest";
import { 
  TopologicalCinemaMaster, 
  advanceFrame, 
  getResolution 
} from "../topological-cinema";

describe("Topological Cinema — The Rotating Barcode", () => {
  test("Triton Shutter is periodic (Order 3)", () => {
    const f = { level: 3, phase: 0 as const };
    expect(TopologicalCinemaMaster.isPeriodic(f)).toBe(true);
    
    const f1 = advanceFrame(f);
    expect(f1.phase).toBe(1);
    
    const f2 = advanceFrame(f1);
    expect(f2.phase).toBe(2);
    
    const f3 = advanceFrame(f2);
    expect(f3.phase).toBe(0);
  });

  test("Bizarro Interpolation produces sub-sample motion", () => {
    // Position 10 (Closure)
    expect(TopologicalCinemaMaster.hasMotion(10)).toBe(true);
  });

  test("Pleromatic Zoom matches closure tower recursion", () => {
    expect(getResolution(0)).toBe(10);
    expect(getResolution(1)).toBe(30);
    expect(getResolution(2)).toBe(90);
    expect(getResolution(3)).toBe(270); // The Monster Mesh standard
  });

  test("Playback sequence generates 3-phase cycle", () => {
    const start = { level: 3, phase: 0 as const };
    const sequence = TopologicalCinemaMaster.getPlaybackSample(start, 4);
    
    expect(sequence).toHaveLength(4);
    expect(sequence[0].phase).toBe(0);
    expect(sequence[1].phase).toBe(1);
    expect(sequence[2].phase).toBe(2);
    expect(sequence[3].phase).toBe(0);
  });
});
